// === CHUNKING + BYPASS: Todo-en-Uno ===
// Corta el texto en pedazos, llama a Ollama UNO POR UNO via HTTP directo,
// y acumula el resultado con la tecnica Refine.

const texto = $input.first().json.body.meeting_text;
const CHUNK_SIZE = 6000;
const OVERLAP = 300;

// 1) Cortar texto en chunks
const chunks = [];
let start = 0;
while (start < texto.length) {
  const end = Math.min(start + CHUNK_SIZE, texto.length);
  chunks.push(texto.substring(start, end));
  if (end >= texto.length) break;
  start = end - OVERLAP;
}

// 2) Procesar cada chunk secuencialmente (Refine)
let accumulated = '';

for (let i = 0; i < chunks.length; i++) {
  let prompt = '';

  if (i === 0 || !accumulated) {
    // Prompt inicial: primera lectura
    prompt = 'Sos un generador de minutas profesionales. No asumas el contexto: puede ser una reunion interna, con proveedores, clientes o tecnicos. Usa solo la informacion disponible en el texto.\n\nA partir del siguiente fragmento de una transcripcion de reunion, arma una primera version de la minuta extrayendo participantes, temas discutidos y decisiones fundamentales:\n\n"' + chunks[i] + '"\n\nFormato de salida:\n---MINUTA---\n(texto de la minuta)\n\n---JSON---\n(json valido con: tipo_reunion, participantes, decisiones, requerimientos, acciones, riesgos, pendientes)';
  } else {
    // Prompt de refinamiento: acumular info
    prompt = 'Tenemos una minuta preliminar creada hasta el momento:\n"' + accumulated + '"\n\nTenemos mas contexto de la reunion a continuacion:\n------------\n"' + chunks[i] + '"\n------------\nDado este nuevo fragmento de texto, refine y amplie la minuta original con la nueva informacion.\nIMPORTANTE: Siempre en tu respuesta final, mantene y combina todo en esta estructura EXACTA:\n\n---MINUTA---\n(la suma de tu minuta original + el nuevo texto)\n\n---JSON---\n(un json valido con: tipo_reunion, participantes, decisiones, requerimientos, acciones, riesgos, pendientes)';
  }

  // Llamada HTTP directa a Ollama (sin LangChain, sin timeout de 5 min)
  const response = await $helpers.httpRequest({
    method: 'POST',
    url: 'http://ollama:11434/api/generate',
    body: {
      model: 'llama3.2',
      stream: false,
      options: { num_ctx: 8192 },
      prompt: prompt
    },
    headers: { 'Content-Type': 'application/json' },
    timeout: 600000
  });

  accumulated = response.response || '';
}

// 3) Parsear el resultado final acumulado
let minuta = 'No se pudo extraer el texto de la minuta';
let data_json = {};

if (accumulated.includes('---MINUTA---')) {
  const splitMinuta = accumulated.split('---MINUTA---')[1];
  if (splitMinuta) {
    if (splitMinuta.includes('---JSON---')) {
      minuta = splitMinuta.split('---JSON---')[0].trim();
    } else {
      minuta = splitMinuta.trim();
    }
  }
} else {
  const braceIdx = accumulated.indexOf('{');
  if (braceIdx > 0) {
    minuta = accumulated.substring(0, braceIdx).trim();
  } else {
    minuta = accumulated.trim();
  }
}

try {
  let raw = accumulated;
  if (raw.includes('```json')) {
    const partes = raw.split('```json');
    if (partes.length > 1) raw = partes[1].split('```')[0];
  }
  const firstBrace = raw.indexOf('{');
  const lastBrace = raw.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1) {
    data_json = JSON.parse(raw.substring(firstBrace, lastBrace + 1));
  } else {
    data_json = { error: 'No JSON found' };
  }
} catch (e) {
  data_json = { error: String(e) };
}

return [{
  json: {
    minuta: minuta,
    json: data_json,
    raw_llm_text: accumulated,
    chunks_procesados: chunks.length
  }
}];
